+
+    // ================================================================
+    // AsyncFilter
+    // ================================================================
+
+    #[test]
+    fn async_filter_new() {
+        let af = AsyncFilter::new(MockSvc, |_: &()| true);
+        let _ = af.inner();
+    }
+
+    #[test]
+    fn async_filter_inner_mut() {
+        let mut af = AsyncFilter::new(42u32, |_: &()| true);
