+
+    #[test]
+    fn async_filter_debug() {
+        let af = AsyncFilter::new(MockSvc, |_: &()| true);
+        let dbg = format!("{af:?}");
+        assert!(dbg.contains("AsyncFilter"));
+    }
+}

